import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const lessonData = {
  // ... 保持原有的 lessonData 不变 ...
};

export default function VideoPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const currentId = parseInt(id || "1");
  const maxLessonId = Object.keys(lessonData).length;
  const nextId = currentId + 1 > maxLessonId ? 1 : currentId + 1;

  const navigateToNextLesson = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    navigate(`/video/${nextId}`);
  };

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [id]);

  const { videoUrl, quiz } = lessonData[currentId] || lessonData[1];
  const [answers, setAnswers] = useState(Array(quiz.length).fill(null));
  const [submitted, setSubmitted] = useState(false);
  const [aiHelpIndex, setAiHelpIndex] = useState(null);
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const handleOptionChange = (index, option) => {
    const newAnswers = [...answers];
    newAnswers[index] = option;
    setAnswers(newAnswers);
  };

  const handleSubmit = () => {
    setSubmitted(true);
    setAiHelpIndex(null);
  };

  const fetchAIHelp = async (question, userAnswer, correctAnswer, helpText) => {
    setIsAiLoading(true);
    setAiHelpIndex(null);
    
    try {
      const response = await fetch('https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${process.env.REACT_APP_DASHSCOPE_API_KEY || '你的API密钥'}`,
        },
        body: JSON.stringify({
          model: 'qwen-turbo',
          messages: [
            {
              role: 'system',
              content: `你是一名网络安全教育助手，正在教授第${currentId}课。请用简单易懂的方式解释问题，使用表情符号和例子。`
            },
            {
              role: 'user',
              content: `问题: ${question}\n我的回答: ${userAnswer}\n正确答案: ${correctAnswer}\n提示: ${helpText}\n请帮我解释为什么正确答案是正确的，并用简单的方式说明这个概念。`
            }
          ]
        })
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }

      const data = await response.json();
      setAiResponse(data.choices[0].message.content);
      setAiHelpIndex(aiHelpIndex); // 重新设置帮助索引以显示响应
    } catch (error) {
      console.error('API Error:', error);
      setAiResponse("抱歉，我暂时无法获取帮助信息。请稍后再试。");
      setAiHelpIndex(aiHelpIndex);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleAiHelpClick = (index) => {
    setAiHelpIndex(index);
    const question = quiz[index].question;
    const userAnswer = answers[index] !== null ? quiz[index].options[answers[index]] : "未回答";
    const correctAnswer = quiz[index].options[quiz[index].answer];
    const helpText = quiz[index].help;
    
    fetchAIHelp(question, userAnswer, correctAnswer, helpText);
  };

  const score = answers.reduce((acc, cur, idx) => {
    return cur === quiz[idx].answer ? acc + 2 : acc;
  }, 0);

  return (
    <div className="content-card">
      <div style={styles.container}>
        <h2 style={styles.title}>📹 Lesson {currentId} - Watch & Quiz</h2>

        {/* 视频区域 */}
        <div style={styles.videoWrapper}>
          <iframe
            width="100%"
            height="315"
            src={videoUrl}
            title={`Lesson ${currentId}`}
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
            style={styles.iframe}
          ></iframe>
        </div>

        {/* 问题区 */}
        <div style={styles.quizSection}>
          {quiz.map((q, index) => (
            <div key={index} style={styles.questionBlock}>
              <p><strong>{q.question}</strong></p>
              {q.options.map((opt, optIdx) => (
                <label key={optIdx} style={styles.option}>
                  <input
                    type="radio"
                    name={`question-${index}`}
                    value={optIdx}
                    disabled={submitted}
                    checked={answers[index] === optIdx}
                    onChange={() => handleOptionChange(index, optIdx)}
                    style={styles.radioInput}
                  />
                  {opt}
                </label>
              ))}
              {submitted && answers[index] !== q.answer && (
                <p style={styles.wrongAnswer}>❌ Wrong answer</p>
              )}
              <button
                style={styles.helpButton}
                onClick={() => handleAiHelpClick(index)}
                disabled={submitted && answers[index] === q.answer}
              >
                {isAiLoading && aiHelpIndex === index ? '🤖 AI正在思考...' : '🤖 Ask AI for help'}
              </button>
              {aiHelpIndex === index && (
                <div style={styles.aiResponse}>
                  <p><strong>AI助手:</strong> {aiResponse || "正在获取帮助信息..."}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 提交与导航 */}
        {!submitted ? (
          <button onClick={handleSubmit} style={styles.submitButton}>
            Submit
          </button>
        ) : (
          <p style={styles.score}>Your score: {score} / {quiz.length * 2}</p>
        )}

        <button
          onClick={navigateToNextLesson}  
          style={styles.nextButton}
        >
          ▶️ Next Lesson →
        </button>
      </div>
    </div>
  );
}

const styles = {
  // ... 保持原有的样式对象不变 ...
};
